import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.internal.bind.JsonTreeWriter;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonTreeWriterTest {
  private JsonTreeWriter writer;

  @BeforeEach
  public void setUp() {
    writer = new JsonTreeWriter();
  }

  @Test
  public void nullValue_shouldPutJsonNullInstanceAndReturnThis() throws Exception {
    JsonWriter returned = writer.nullValue();
    assertSame(writer, returned);

    // Use reflection to access private field 'stack'
    Field stackField = JsonTreeWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<JsonElement> stack = (List<JsonElement>) stackField.get(writer);

    // The stack should contain JsonNull.INSTANCE as last element
    assertFalse(stack.isEmpty());
    assertSame(JsonNull.INSTANCE, stack.get(stack.size() - 1));
  }

  @Test
  public void nullValue_shouldInvokePrivatePutWithJsonNullInstance() throws Exception {
    // Spy on the writer to verify private method invocation indirectly
    JsonTreeWriter spyWriter = spy(writer);

    // Call nullValue()
    spyWriter.nullValue();

    // Use reflection to get private method put
    Method putMethod = JsonTreeWriter.class.getDeclaredMethod("put", JsonElement.class);
    putMethod.setAccessible(true);

    // Verify put was called with JsonNull.INSTANCE
    // Since put is private, verify invocation via spy using doCallRealMethod and verify
    // Mockito cannot verify private method calls directly, so we verify the effect on stack instead
    Field stackField = JsonTreeWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<JsonElement> stack = (List<JsonElement>) stackField.get(spyWriter);

    assertFalse(stack.isEmpty());
    assertSame(JsonNull.INSTANCE, stack.get(stack.size() - 1));
  }

  @Test
  public void nullValue_shouldThrowIOException_whenPutThrowsIOException() throws Exception {
    // Create a subclass to override put and throw IOException
    JsonTreeWriter writerWithException = new JsonTreeWriter() {
      @Override
      protected void put(JsonElement value) throws IOException {
        throw new IOException("forced IOException");
      }
    };

    IOException thrown = assertThrows(IOException.class, writerWithException::nullValue);
    assertEquals("forced IOException", thrown.getMessage());
  }
}
